changeSet.sql:
INSERT INTO poc_entrance (entrance_name, description, location_id) VALUES ('Main Entrance', 'Primary public access point for visiting guests', (SELECT TOP 1 id FROM poc_location WHERE name = 'Commanders Desk'));
INSERT INTO poc_entrance (entrance_name, description, location_id) VALUES ('North Gate', 'Staff and authorised vehicle access, north perimeter', (SELECT TOP 1 id FROM poc_location WHERE name = 'Commanders Desk'));
INSERT INTO poc_entrance (entrance_name, description, location_id) VALUES ('South Gate', 'Emergency services and logistics access, south perimeter', (SELECT TOP 1 id FROM poc_location WHERE name = 'Commanders Desk'));
INSERT INTO poc_entrance (entrance_name, description, location_id) VALUES ('East Wing Lobby', 'Client reception and conference room level', (SELECT TOP 1 id FROM poc_location WHERE name = 'Commanders Desk'));
INSERT INTO poc_entrance (entrance_name, description, location_id) VALUES ('West Wing Lobby', 'Operations and research departments access', (SELECT TOP 1 id FROM poc_location WHERE name = 'Commanders Desk'));
INSERT INTO poc_entrance (entrance_name, description, location_id) VALUES ('Loading Dock Alpha', 'Inbound goods and deliveries, ground floor', (SELECT TOP 1 id FROM poc_location WHERE name = 'Commanders Desk'));
INSERT INTO poc_entrance (entrance_name, description, location_id) VALUES ('Loading Dock Bravo', 'Outbound shipments and collections, ground floor', (SELECT TOP 1 id FROM poc_location WHERE name = 'Commanders Desk'));
INSERT INTO poc_entrance (entrance_name, description, location_id) VALUES ('Executive Floor', 'Restricted zone — board and C-level offices, 12th floor', (SELECT TOP 1 id FROM poc_location WHERE name = 'Commanders Desk'));
INSERT INTO poc_entrance (entrance_name, description, location_id) VALUES ('Server Room Corridor', 'High-security infrastructure and data centre access', (SELECT TOP 1 id FROM poc_location WHERE name = 'Commanders Desk'));
INSERT INTO poc_entrance (entrance_name, description, location_id) VALUES ('Staff Canteen', 'Internal staff access, basement level', (SELECT TOP 1 id FROM poc_location WHERE name = 'Commanders Desk'));

